import{_ as e,o as n,c as t,ae as s}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Custom QR Codes via API","description":"","frontmatter":{"title":"Custom QR Codes via API","slug":"custom-qr-codes-via-api"},"headers":[],"relativePath":"account-hub/custom-qr-codes-via-api.md","filePath":"account-hub/custom-qr-codes-via-api.md"}'),o={name:"account-hub/custom-qr-codes-via-api.md"};function i(p,a,r,c,l,d){return n(),t("div",null,[...a[0]||(a[0]=[s(`<h2 id="overview" tabindex="-1"><strong>Overview</strong> <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;**Overview**&quot;">​</a></h2><p>Branch has updated the <a href="https://help.branch.io/apidocs/quick-links-api" target="_blank" rel="noreferrer">Quick Link (Short Link) API</a> to support QR code customization during link creation. Previously, links created with the API generated a standard black-and-white QR code by default. With this update, developers can programmatically apply branding and design settings to the QR codes associated with their Short Links.</p><p>This update streamlines the workflow for creating branded assets at scale. You can now generate deep links and their corresponding branded QR codes in a single API call, removing the need to manually customize QR codes in Branch after link creation.</p><h2 id="how-it-works" tabindex="-1"><strong>How it works</strong> <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;**How it works**&quot;">​</a></h2><p>When creating a link, you can include the <code>qr_code_settings</code> object in the request. This object accepts the same styling parameters as the <a href="https://help.branch.io/apidocs/qr-code-api" target="_blank" rel="noreferrer">QR Code API</a>.</p><p>When you create a Short Link with <code>qr_code_settings</code>, both the Short Link and its customized QR code are generated instantly and appear in Branch.</p><h3 id="example-api-request" tabindex="-1"><strong>Example API request</strong> <a class="header-anchor" href="#example-api-request" aria-label="Permalink to &quot;**Example API request**&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>curl -XPOST https://api2.branch.io/v1/url \\</span></span>
<span class="line"><span>  -H &quot;Content-Type: application/json&quot; \\</span></span>
<span class="line"><span>  -d &#39;{</span></span>
<span class="line"><span>  &quot;branch_key&quot;: &quot;key_live_kaFuWw8WvY7yn1d9yYiP8gokwqjV0Swt&quot;,</span></span>
<span class="line"><span>  &quot;channel&quot;: &quot;facebook&quot;,</span></span>
<span class="line"><span>  &quot;feature&quot;: &quot;onboarding&quot;,</span></span>
<span class="line"><span>  &quot;campaign&quot;: &quot;new product&quot;,</span></span>
<span class="line"><span>  &quot;type&quot;: 2,</span></span>
<span class="line"><span>  &quot;data&quot;: {</span></span>
<span class="line"><span>    &quot;$marketing_title&quot;: &quot;My QR Code via API&quot;,</span></span>
<span class="line"><span>    &quot;$desktop_url&quot;: &quot;http://www.example.com&quot;</span></span>
<span class="line"><span>  },</span></span>
<span class="line"><span>  &quot;qr_code_settings&quot;: {</span></span>
<span class="line"><span>    &quot;code_pattern&quot;: 1,</span></span>
<span class="line"><span>    &quot;finder_pattern&quot;: 2,</span></span>
<span class="line"><span>    &quot;finder_pattern_color&quot;: &quot;#D94280&quot;,</span></span>
<span class="line"><span>    &quot;frame_style&quot;: 1,</span></span>
<span class="line"><span>    &quot;code_shape&quot;: 1,</span></span>
<span class="line"><span>    &quot;code_color&quot;: &quot;#D94280&quot;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}&#39;</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Note</p><p>In the API call, you must specify <code>type=2</code> to customize a QR code.</p></div><h2 id="availability" tabindex="-1"><strong>Availability</strong> <a class="header-anchor" href="#availability" aria-label="Permalink to &quot;**Availability**&quot;">​</a></h2><p>This feature is available to customers with <a href="./products.html#engagement">Engagement Pro</a>, or those with access to both the Quick Link (Short Link) API and QR Codes API.</p><p>All users with access can view and download the customized QR codes in Branch.</p><p>The ability to edit QR codes created with an API depends on which Branch interface you currently have:</p><ul><li><strong>Activation Essentials or New Branch</strong>: Users can edit the QR code design directly within Branch after creation.</li><li><strong>Legacy Branch</strong>: The QR code design is read-only in legacy Branch. To edit the design, you must update the link via the API or delete and create it again.</li></ul><div class="info custom-block"><p class="custom-block-title">Note</p><p>This feature is not available in the Deep Linking API.</p></div>`,15)])])}const q=e(o,[["render",i]]);export{h as __pageData,q as default};
